import React from 'react';
import { useNavigate } from 'react-router-dom';

const features = [
  {
    icon: '📄',
    title: 'Document Analyzer',
    desc: 'Upload any legal document — rental agreement, employment contract, legal notice. Get clause-by-clause risk scoring and plain-language explanation.',
    path: '/analyze',
  },
  {
    icon: '⚖️',
    title: 'BNS Compliance Check',
    desc: 'Check if your legal document uses obsolete IPC/CrPC sections. Get the correct BNS 2023 equivalents and a compliance score.',
    path: '/compliance',
  },
  {
    icon: '🔐',
    title: 'Evidence Certificate',
    desc: 'Generate a SHA-256 cryptographic certificate for your evidence under BSA Section 63 — making it court-admissible.',
    path: '/evidence',
  },
];

const stats = [
  { number: '18+',  label: 'BNS Offences Covered' },
  { number: '70+',  label: 'IPC→BNS Mappings' },
  { number: '100%', label: 'BSA Sec 63 Compliant' },
  { number: 'Free', label: 'No Registration Needed' },
];

export default function Home() {
  const navigate = useNavigate();

  return (
    <div>
      {/* Hero */}
      <div className="hero">
        <h1 className="hero-title">
          Nyaya<span>Setu</span>
        </h1>
        <p className="hero-subtitle">
          AI-Powered Indian Legal Document Analyzer.<br />
          Understand your rights. Identify risks. Get plain-language guidance — instantly.
        </p>
        <div className="flex gap-2" style={{ justifyContent: 'center' }}>
          <button className="btn btn-primary" onClick={() => navigate('/analyze')}>
            📄 Analyze a Document
          </button>
          <button className="btn btn-outline" onClick={() => navigate('/compliance')}>
            ⚖️ Check BNS Compliance
          </button>
        </div>
      </div>

      {/* Stats */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 16, marginBottom: 32 }}>
        {stats.map((s, i) => (
          <div key={i} className="card" style={{ textAlign: 'center' }}>
            <div style={{ fontSize: '1.8rem', fontWeight: 700, color: 'var(--navy)' }}>{s.number}</div>
            <div className="text-grey">{s.label}</div>
          </div>
        ))}
      </div>

      {/* Features */}
      <h2 className="section-title">What can Nyaya-Setu do for you?</h2>
      <div className="feature-grid">
        {features.map((f, i) => (
          <div key={i} className="feature-card" onClick={() => navigate(f.path)}>
            <div className="feature-icon">{f.icon}</div>
            <div className="feature-title">{f.title}</div>
            <div className="feature-desc">{f.desc}</div>
          </div>
        ))}
      </div>

      {/* Disclaimer */}
      <div style={{ 
        marginTop: 40, 
        padding: '14px 20px', 
        background: 'var(--ltorange)', 
        borderRadius: 'var(--radius)',
        fontSize: '0.85rem',
        color: 'var(--orange)',
        border: '1px solid #FCD34D'
      }}>
        ⚠️ <strong>Disclaimer:</strong> Nyaya-Setu provides AI-generated legal guidance for informational purposes only. 
        It does not constitute legal advice. For important legal matters, always consult a qualified Indian advocate.
      </div>
    </div>
  );
}
